outline\"></i></el-input>\r\n                            <small class=\"text-danger\" v-if=\"errors.item_code\" v-text=\"errors.item_code[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                 \r\n\r\n                    <div class=\"col-md-3\" v-show=\"form.unit_type_id !='ZZ'\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.stock_min}\">\r\n                            <label class=\"control-label\">Stock Mínimo</label>\r\n                            <el-input v-model=\"form.stock_min\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                            <small class=\"text-danger\" v-if=\"errors.stock_min\" v-text=\"errors.stock_min[0]\"></small>\r\n                        </div>\r\n                    </div>-->\r\n\r\n                            <div class=\"col-md-3\" v-show=\"recordId == null\" v-if=\"form.unit_type_id != 'ZZ'\">\r\n                                <div class=\"form-group\" :class=\"{\r\n                                    'has-danger': errors.warehouse_id\r\n                                }\">\r\n                                    <label class=\"control-label\">\r\n                                        Almacén\r\n                                        <el-tooltip class=\"item\" effect=\"dark\"\r\n                                            content=\"Si no selecciona almacén, se asignará por defecto el relacionado al establecimiento\"\r\n                                            placement=\"top\">\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-select @change=\"changeWarehouse\" v-model=\"form.warehouse_id\">\r\n                                        <el-option v-for=\"option in warehouses\" :key=\"option.id\" :value=\"option.id\"\r\n                                            :label=\"option.description\"></el-option>\r\n                                    </el-select>\r\n                                    <small class=\"text-danger\" v-if=\"errors.warehouse_id\"\r\n                                        v-text=\"errors.warehouse_id[0]\"></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div class=\"col-md-3\" v-show=\"form.unit_type_id != 'ZZ'\">\r\n                                <div class=\"form-group\" :class=\"{\r\n                                    'has-danger': errors.date_of_due\r\n                                }\">\r\n                                    <label class=\"control-label\">Fec. Vencimiento</label>\r\n                                    <el-date-picker v-model=\"form.date_of_due\" type=\"date\" value-format=\"yyyy-MM-dd\"\r\n                                        :clearable=\"true\"></el-date-picker>\r\n                                    <small class=\"text-danger\" v-if=\"errors.date_of_due\"\r\n                                        v-text=\"errors.date_of_due[0]\"></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\" v-show=\"form.unit_type_id != 'ZZ'\">\r\n                                <div class=\"form-group\">\r\n                                    <label class=\"control-label\">Cantidad Máxima\r\n                                        <el-tooltip class=\"item\" effect=\"dark\"\r\n                                            content=\"La cantidad máxima representada en el envase/contenedor\"\r\n                                            placement=\"top\">\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-input :disabled=\"\r\n                                        form.item_unit_types.length != 0\r\n                                    \" v-model=\"form.max_quantity\"></el-input>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"d-flex\" v-if=\"showSeries\">\r\n                                <div class=\"col-md-4\">\r\n                                    <div v-show=\"form.unit_type_id != 'ZZ'\" class=\"col-md-3 center-el-checkbox\">\r\n                                        <div class=\"form-group\">\r\n                                            <el-checkbox  v-model=\"form.series_enabled\"\r\n                                                @change=\"changeLotsEnabled\">¿Maneja series?</el-checkbox><br />\r\n                                        </div>\r\n                                    </div>\r\n                                    <div class=\"col-md-4 d-flex align-items-end\" v-if=\"\r\n                                        form.unit_type_id != 'ZZ' &&\r\n                                        form.series_enabled\r\n                                    \">\r\n                                        <div class=\"form-group \" :class=\"{\r\n                                            'has-danger': errors.lot_code\r\n                                        }\">\r\n                                            <label class=\"control-label\">\r\n                                                Ingrese series\r\n                                            </label>\r\n\r\n                                            <el-button style=\"margin-top:2%;margin-left:15px;\" type=\"primary\"\r\n                                                icon=\"el-icon-edit-outline\" @click.prevent=\"clickLotcode\"></el-button>\r\n\r\n                                            <small class=\"text-danger\" v-if=\"errors.lot_code\"\r\n                                                v-text=\"errors.lot_code[0]\"></small>\r\n                  